parameters.jsCode:
const staticData = $getWorkflowStaticData('global');
const now = Date.now();
const windowMs = 10000;
const limit = 10;
const maxInputLength = 2000;

const firstItem = items[0];
const body = (firstItem && firstItem.json && firstItem.json.body) || {};
const contactId = body.remoteJid || 'unknown';

if (!staticData.rateLimits) staticData.rateLimits = {};
if (!staticData.rateLimits[contactId] || (now - staticData.rateLimits[contactId].windowStart) > windowMs) {
  staticData.rateLimits[contactId] = { windowStart: now, count: 0 };
}
staticData.rateLimits[contactId].count += 1;

const rateLimited = staticData.rateLimits[contactId].count > limit;

for (const item of items) {
  item.json.rateLimited = rateLimited;
  if (item.json.body && typeof item.json.body.chatInput === 'string' && item.json.body.chatInput.length > maxInputLength) {
    item.json.body.chatInput = item.json.body.chatInput.slice(0, maxInputLength) + '... [message truncated]';
  }
}

return items;

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessionContext) staticData.sessionContext = {};

const EXPIRY_MS = 1000 * 60 * 60 * 24; // 24h — flags older than this are treated as a new conversation

const item = items[0];
const category = item.json.output && item.json.output.category;
const contactId = $('Edit Fields').first().json.Phone || 'unknown';

if (!staticData.sessionContext[contactId]) {
  staticData.sessionContext[contactId] = {};
}
const session = staticData.sessionContext[contactId];

if (session.lastInteractionAt && (Date.now() - session.lastInteractionAt) > EXPIRY_MS) {
  delete session.greeted;
  delete session.askedGeneralPrice;
}

if (category === 'greeting') session.greeted = true;
if (category === 'services') session.askedGeneralPrice = true;
session.lastCategory = category;
session.lastInteractionAt = Date.now();

const notes = [];
if (session.greeted) notes.push('the customer was already greeted in this session');
if (session.askedGeneralPrice) notes.push('the customer already received the general bath/grooming prices before');

const sessionContextNote = notes.length ? ('Session context: ' + notes.join('; ') + '.') : '';

for (const it of items) {
  it.json.sessionContextNote = sessionContextNote;
}

return items;
